// ── PI SDK WRAPPER ────────────────────────────────────────────────
const PiSDK = {
  isAvailable: () => typeof window !== "undefined" && typeof window.Pi !== "undefined",
  init: () => {
    if (PiSDK.isAvailable()) {
      window.Pi.init({ version: "2.0", sandbox: true });
      return true;
    }
    return false;
  },
  authenticate: async (scopes) => {
    if (PiSDK.isAvailable()) {
      return await window.Pi.authenticate(scopes, (payment) => {
        console.log("Incomplete payment found:", payment);
      });
    }
    // Demo mode fallback
    return { user: { uid: "demo_user_001", username: "demo_pioneer" }, accessToken: "demo_token" };
  },
  createPayment: async ({ amount, memo, metadata }, callbacks) => {
    if (PiSDK.isAvailable()) {
      return window.Pi.createPayment({ amount, memo, metadata }, callbacks);
    }
    // Demo mode: simulate payment flow
    await new Promise(r => setTimeout(r, 1200));
    const paymentId = "demo_pay_" + Date.now();
    callbacks?.onReadyForServerApproval?.(paymentId);
    await new Promise(r => setTimeout(r, 800));
    callbacks?.onReadyForServerCompletion?.(paymentId, "demo_tx_" + Date.now());
    return { identifier: paymentId, status: { developer_approved: true } };
  }
};

