// ── HELPERS ───────────────────────────────────────────────────────
const fmt = (fcfa, code, rates) => {
  const r = rates || REF_RATES;
  if (code==="FCFA") return `${Math.round(fcfa).toLocaleString("fr-FR")} FCFA`;
  if (code==="PI")   return `${(fcfa/PI_GCV_FCFA).toFixed(6).replace(/\.?0+$/,"")} π`;
  const sym = CURRENCIES.find(c=>c.code===code)?.sym||"";
  return `${sym} ${(fcfa/(r[code]||REF_RATES[code]||1)).toLocaleString("fr-FR",{minimumFractionDigits:2,maximumFractionDigits:2})}`;
};

