const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;500;600;700;800;900&display=swap');
*{box-sizing:border-box;margin:0;padding:0;}
body{background:#03070F;}
::-webkit-scrollbar{width:3px;}
::-webkit-scrollbar-thumb{background:#112035;border-radius:2px;}
input,textarea{font-family:'Sora',sans-serif;color:#D6E4F5;}
input::placeholder,textarea::placeholder{color:#3E5E84;opacity:.7;}
@keyframes fadeUp{from{opacity:0;transform:translateY(8px);}to{opacity:1;transform:translateY(0);}}
@keyframes blink{0%,100%{opacity:1;}50%{opacity:.3;}}
@keyframes slideUp{from{opacity:0;transform:translateY(20px);}to{opacity:1;transform:translateY(0);}}
.fade{animation:fadeUp .28s ease both;}
.tap{cursor:pointer;transition:all .15s ease;user-select:none;-webkit-tap-highlight-color:transparent;}
.tap:hover{opacity:.82;}
.tap:active{transform:scale(.96);}
.blink{animation:blink 1.2s infinite;}
.chat-in{animation:slideUp .2s ease both;}
`;

